import math

def get_divisors(n):
    divisors = set()
    for i in range(1, int(math.isqrt(n)) + 1):
        if n % i == 0:
            divisors.add(i)
            divisors.add(n // i)
    return sorted(divisors)

def solve():
    n = int(input())
    min_result = float('inf')
    max_result = 0
    divisors = get_divisors(n)
    for k in divisors:
        m = n // k
        sub_divisors = get_divisors(k)
        for d in sub_divisors:
            if d * d > k:
                continue
            if k % d != 0:
                continue
            e = k // d
            a = m + 1
            b = d + 2
            c = e + 2
            stolen = a * b * c - n
            if stolen < min_result:
                min_result = stolen
            if stolen > max_result:
                max_result = stolen
    print(min_result, max_result)

