PRIME = -1
N = 10**9
primes = [PRIME for _ in range(N + 1)]


def factor(n):
    if n == 1:
        return []
    if primes[n] == PRIME:
        return [(n, 1)]
    result = []
    result.append((primes[n], 1))
    n //= primes[n]
    while primes[n] != PRIME:
        if result[-1][0] == primes[n]:
            result[-1] = (primes[n], result[-1][1] + 1)
        else:
            result.append((primes[n], 1))
        n //= primes[n]
    if result[-1][0] == n:
        result[-1] = (n, result[-1][1] + 1)
    else:
        result.append((n, 1))
